import re, csv
from collections import defaultdict
meta = {row["label"]:row for row in csv.DictReader(open("nif3_metadata.csv"))}

# Monophyly checks using dendropy on the ML tree
import dendropy
taxa = dendropy.TaxonNamespace()
tr = dendropy.Tree.get(path="nif3.treefile", schema="newick", taxon_namespace=taxa)
tr.reroot_at_midpoint(update_bipartitions=True)

def labels_in(domain):
    return {l for l,m in meta.items() if m["domain"]==domain}

def is_monophyletic(label_set):
    leaves = [lf for lf in tr.leaf_node_iter() if lf.taxon.label.replace(" ","_") in label_set or lf.taxon.label in label_set]
    if len(leaves)<2: return None
    mrca = tr.mrca(taxa=[lf.taxon for lf in leaves])
    desc = {lf.taxon.label for lf in mrca.leaf_iter()}
    want = {lf.taxon.label for lf in leaves}
    return desc==want, len(desc), len(want)

for d in ["Archaea","Bacteria","Eukarya"]:
    ls = labels_in(d)
    # dendropy uses spaces? check
    print(d, "n=",len(ls), "monophyletic:", is_monophyletic(ls))

