import urllib.request, json
# Fetch full UniProt JSON for E. coli YbgI (P0AFP6) and MJ0927 (Q58337) to get metal-binding features
def uniprot_json(acc):
    url=f"https://rest.uniprot.org/uniprotkb/{acc}.json"
    req=urllib.request.Request(url, headers={"User-Agent":"operon-phylo/1.0"})
    return json.load(urllib.request.urlopen(req, timeout=60))

for acc in ["P0AFP6","Q58337"]:
    j=uniprot_json(acc)
    print("="*60); print(acc, j["proteinDescription"]["recommendedName"]["fullName"]["value"])
    for feat in j.get("features",[]):
        if feat["type"] in ("Binding site","Metal binding","Active site","Site"):
            loc=feat["location"]
            pos = loc.get("start",{}).get("value")
            end = loc.get("end",{}).get("value")
            desc = feat.get("description","")
            lig = feat.get("ligand",{}).get("name","")
            print(f'  {feat["type"]:14} {pos}-{end}  ligand={lig}  {desc}')

